#include <stdio.h>
#define MOD 100000000
typedef long long int ll;

ll army[101][101][2];

int min(a, b)
{
    if(a < b)
    {
        return a;
    }
    else
    {
        return b;
    }
}

ll count(ll army[101][101][2], int n1, int n2, int l1, int l2, int t)
{
    ll res = 0;
    int i, edge;
    if(army[n1][n2][t] == -1)
    {
        if(t == 0)
        {
            edge = min(n1, l1);
            for(i = 1; i <= edge; i++)
            {
                res = (res + count(army, n1 - i, n2, l1, l2, !t)) % MOD;
            }
        }
        else
        {
            edge = min(n2, l2);
            for(i = 1; i <= edge; i++)
            {
                res = (res + count(army, n1, n2 - i, l1, l2, !t)) % MOD;
            }
        }
        army[n1][n2][t] = res;
    }
    return army[n1][n2][t];
}

void init(ll army[101][101][2], int n1, int n2, int l1, int l2)
{
    int i, j;
    for(i = 0; i <= n1; i++)
    {
        for(j = 0; j <= n2; j++)
        {
            if(i == 0 && j > 0)
            {
                army[i][j][0] = 0;
            }
            else if(i >= 0 && i <= l1 && j == 0)
            {
                army[i][j][0] = 1;
            }
            else if(i > l1 && j == 0)
            {
                army[i][j][0] = 0;
            }
            else
            {
                army[i][j][0] = -1;
            }
        }
    }
    for(i = 0; i <= n1; i++)
    {
        for(j = 0; j <= n2; j++)
        {
            if(j == 0 && i > 0)
            {
                army[i][j][1] = 0;
            }
            else if(j >= 0 && j <= l2 && i == 0)
            {
                army[i][j][1] = 1;
            }
            else if(j > l2 && i == 0)
            {
                army[i][j][1] = 0;
            }
            else
            {
                army[i][j][1] = -1;
            }
        }
    }
}

int main()
{
    int n1, n2, l1, l2;
    ll res;
    scanf("%d %d %d %d", &n1, &n2, &l1, &l2);
    init(army, n1, n2, l1, l2);
    res = (count(army, n1, n2, l1, l2, 0) + count(army, n1, n2, l1, l2, 1)) % MOD;
    printf("%I64d\n", res);
    return 0;
}

