fn main() {
    let mut bin = String::new();
    let mut input = WordReader::from_stdin(&mut bin);

    const MAX_N: usize = 104;
    const MAX_K: usize = 12;

    let id = |n1, n2, w, k| {
        ((n1 * MAX_N + n2) * 2 + w) * MAX_K + k
    };
    let mut dp = vec![Field::new_unchecked(0); MAX_N * MAX_N * 2 * MAX_K];

    l!(n1,n2,k1,k2 = input.u());
    let k = [k1, k2];
    dp[id(0,0,0,0)] = Field::new_unchecked(1);

    for i in 0..=n1 {
        for j in 0..=n2 {
            for w in 0..=1 {
                let wk = k[w];
                for l in 0..=wk {
                    let val = dp[id(i, j, w, l)];
                    if val.0 == 0 {
                        continue;
                    }
                    for a in 0..=1 {
                        let ii = i + 1 - a;
                        let jj = j + a;
                        let ll = if a == w {l + 1} else {1};
                        dp[id(ii, jj, a, ll)] += val;
                    }
                }
            }
        }
    }

    let mut sol = Field::new_unchecked(0);
    for w in 0..=1 {
        for l in 0..=k[w] {
            sol += dp[id(n1, n2, w, l)];
        }
    }
    println!("{}", sol);
}
